custom_fields.steps:
[[[
  const stupen = parseInt(entity.state);
  const boxy = Array.from({length: 9}, (_, i) => {
    const active = i <= stupen;
    const color = active ? `hsl(${200 - i*15}, 80%, 45%)` : '#444';
    return `<div style="width:26px;height:26px;border-radius:4px;background:${color};
              display:flex;align-items:center;justify-content:center;
              color:white;font-size:11px;font-weight:bold">${i}</div>`;
  });
  return '<div style="display:flex;gap:6px;justify-content:center;padding:4px 0">' + boxy.join('') + '</div>';
]]]
